#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int X, Y; scanf("%d %d", &X, &Y);
        int ans = (Y <= X) ? Y : X;
        printf("%d\n", ans);
    }
    return 0;
}

